# Full ingestion pipeline: load → clean → chunk → embed → store
# This runs offline whenever source documents are added or updated.

from pathlib import Path
from langchain_community.document_loaders import (
    TextLoader, PyPDFLoader, UnstructuredHTMLLoader
)
from langchain_text_splitters import RecursiveCharacterTextSplitter
from langchain_openai import OpenAIEmbeddings
from langchain_community.vectorstores import Chroma
from langchain_core.documents import Document
import hashlib


def load_document(path: str) -> list[Document]:
    """Load a document based on its file extension."""
    ext = Path(path).suffix.lower()
    if ext == ".pdf":
        return PyPDFLoader(path).load()
    elif ext in (".html", ".htm"):
        return UnstructuredHTMLLoader(path).load()
    else:
        return TextLoader(path, encoding="utf-8").load()


def add_content_hash(doc: Document) -> Document:
    """Add a content hash to metadata for deduplication and change detection."""
    doc.metadata["content_hash"] = hashlib.md5(doc.page_content.encode()).hexdigest()
    return doc


splitter = RecursiveCharacterTextSplitter(
    chunk_size=512,
    chunk_overlap=64,
    separators=["\n\n", "\n", ". ", " "],
    length_function=len,
)

embeddings = OpenAIEmbeddings(model="text-embedding-3-small")
vectorstore = Chroma(
    persist_directory="./chroma_db",
    embedding_function=embeddings,
    collection_name="knowledge_base",
)


def ingest(file_paths: list[str]) -> int:
    """Ingest a list of files. Returns number of chunks indexed."""
    all_chunks = []
    for path in file_paths:
        raw_docs = load_document(path)
        for doc in raw_docs:
            doc.metadata["source"] = path
            add_content_hash(doc)
        chunks = splitter.split_documents(raw_docs)
        all_chunks.extend(chunks)

    vectorstore.add_documents(all_chunks)
    return len(all_chunks)


# Usage
n = ingest(["docs/policy.txt", "docs/faq.pdf"])
print(f"Indexed {n} chunks")

# Full query pipeline: transform → retrieve → rerank → assemble → generate

from langchain_community.vectorstores import Chroma
from langchain_openai import OpenAIEmbeddings, ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from langchain_core.documents import Document
from openai import OpenAI

client = OpenAI()
vectorstore = Chroma(
    persist_directory="./chroma_db",
    embedding_function=OpenAIEmbeddings(model="text-embedding-3-small"),
)


def expand_query(question: str) -> list[str]:
    """Generate 2 rephrasings to improve retrieval recall."""
    resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{
            "role": "user",
            "content": (
                f"Write 2 short search queries to retrieve documents that answer:\n{question}\n"
                "Return one per line, no numbering."
            ),
        }],
        max_tokens=80,
    )
    lines = resp.choices[0].message.content.strip().splitlines()
    return [question] + [l.strip() for l in lines if l.strip()][:2]


def retrieve_and_deduplicate(queries: list[str], k: int = 4) -> list[Document]:
    """Retrieve docs for each query variant and deduplicate by content."""
    seen, results = set(), []
    for q in queries:
        for doc in vectorstore.similarity_search(q, k=k):
            if doc.page_content not in seen:
                seen.add(doc.page_content)
                results.append(doc)
    return results[:k * 2]   # cap total to avoid bloating context


def rerank(question: str, docs: list[Document], top_n: int = 4) -> list[Document]:
    """
    LLM-based reranker: score each doc for relevance to the question (0–10).
    In production, use a cross-encoder (e.g. Cohere Rerank) for lower latency.
    """
    if len(docs) <= top_n:
        return docs
    scores = []
    for doc in docs:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[{
                "role": "user",
                "content": (
                    f"Score this passage 0-10 for relevance to the question.\n"
                    f"Question: {question}\nPassage: {doc.page_content[:300]}\n"
                    "Respond with only a number."
                ),
            }],
            max_tokens=4,
        )
        try:
            score = float(resp.choices[0].message.content.strip())
        except ValueError:
            score = 0.0
        scores.append((score, doc))
    scores.sort(reverse=True)
    return [doc for _, doc in scores[:top_n]]


def assemble_context(docs: list[Document], max_chars: int = 4000) -> str:
    """Concatenate top docs into a context string, truncating if needed."""
    parts = []
    total = 0
    for i, doc in enumerate(docs):
        src = doc.metadata.get("source", "unknown")
        block = f"[{i}] ({src})\n{doc.page_content}"
        if total + len(block) > max_chars:
            break
        parts.append(block)
        total += len(block)
    return "\n\n".join(parts)


PROMPT = ChatPromptTemplate.from_template(
    "Answer using only the context. Cite passage numbers like [0].\n\n"
    "Context:\n{context}\n\nQuestion: {question}"
)
llm = ChatOpenAI(model="gpt-4o-mini")


def rag_query(question: str) -> str:
    queries = expand_query(question)
    candidates = retrieve_and_deduplicate(queries)
    top_docs = rerank(question, candidates)
    context = assemble_context(top_docs)
    return (PROMPT | llm | StrOutputParser()).invoke(
        {"context": context, "question": question}
    )


print(rag_query("What is the enterprise SLA?"))

# Incremental indexing: only re-embed changed or new documents
# Full re-indexing on every document update is expensive for large corpora.
# Use content hashes to detect changes and update only the affected chunks.

from langchain_community.vectorstores import Chroma
from langchain_openai import OpenAIEmbeddings
from langchain_core.documents import Document
import hashlib
import json
from pathlib import Path

HASH_STORE = Path("./index_hashes.json")
embeddings = OpenAIEmbeddings(model="text-embedding-3-small")
vectorstore = Chroma(
    persist_directory="./chroma_db",
    embedding_function=embeddings,
    collection_name="knowledge_base",
)


def load_hashes() -> dict[str, str]:
    if HASH_STORE.exists():
        return json.loads(HASH_STORE.read_text())
    return {}


def save_hashes(hashes: dict[str, str]):
    HASH_STORE.write_text(json.dumps(hashes, indent=2))


def content_hash(text: str) -> str:
    return hashlib.md5(text.encode()).hexdigest()


def incremental_ingest(file_paths: list[str], splitter) -> dict[str, int]:
    """
    Re-index only files that are new or have changed content.
    Returns a summary of what was added, updated, and skipped.
    """
    hashes = load_hashes()
    stats = {"added": 0, "updated": 0, "skipped": 0}

    for path in file_paths:
        text = Path(path).read_text(encoding="utf-8")
        h = content_hash(text)

        if hashes.get(path) == h:
            stats["skipped"] += 1
            continue

        # Delete existing chunks for this source before re-indexing
        if path in hashes:
            existing = vectorstore.get(where={"source": path})
            if existing["ids"]:
                vectorstore.delete(ids=existing["ids"])
            stats["updated"] += 1
        else:
            stats["added"] += 1

        chunks = splitter.split_documents([Document(page_content=text, metadata={"source": path})])
        for chunk in chunks:
            chunk.metadata["content_hash"] = h
        vectorstore.add_documents(chunks)
        hashes[path] = h

    save_hashes(hashes)
    return stats


from langchain_text_splitters import RecursiveCharacterTextSplitter
splitter = RecursiveCharacterTextSplitter(chunk_size=512, chunk_overlap=64)

result = incremental_ingest(["docs/policy.txt", "docs/faq.txt"], splitter)
print(f"Indexing result: {result}")
# On first run: {"added": 2, "updated": 0, "skipped": 0}
# On re-run with no changes: {"added": 0, "updated": 0, "skipped": 2}
# On re-run after editing faq.txt: {"added": 0, "updated": 1, "skipped": 1}
